<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net8.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.405" />
  </ItemGroup>
</Project>
EOF
cat > Program.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD ERRORS ===");
build.VisitAllChildren<Error>(e => {
    Console.WriteLine($"[ERROR] {e.File}({e.LineNumber},{e.ColumnNumber}): {e.Code}: {e.Text} [{e.ProjectFile}]");
});

Console.WriteLine("\n=== BUILD WARNINGS ===");
build.VisitAllChildren<Warning>(w => {
    Console.WriteLine($"[WARN] {w.File}({w.LineNumber},{w.ColumnNumber}): {w.Code}: {w.Text} [{w.ProjectFile}]");
});

Console.WriteLine("\n=== PROJECT RESULTS ===");
build.VisitAllChildren<Project>(p => {
    Console.WriteLine($"Project: {p.Name} - Succeeded: {p.Succeeded}");
});
EOF
